PlayerProperty = class("PlayerProperty")

local exchangeRewardMap = {
    [Define.PayItemType.AutoWorkout] = "AutoWorkout",
    [Define.PayItemType.ConcealPower] = "ConcealPower",
    [Define.PayItemType.DoubleSpeed] = "DoubleSpeed",
    [Define.PayItemType.DoubleGold] = "DoubleGold",
    [Define.PayItemType.DoubleMuscle] = "DoubleMuscle",
}

function PlayerProperty:ctor(userId)
    self.userId = userId

    --付费功能
    self.payItemList = {}
    self.skinList = {}
    self.isConcealPower = false
    self.skinId = -1
    self.loadDataFinish = false
    self.showSelectSkinDlg = true --是否显示选择皮肤对话框

    self.muscleMassCoe = GameConfig.muscleMassCoe --肌肉量系数
    self.geneId = GeneConfig:getFirstGeneId() --基因id
    self.fitnessEquipId = FitnessEquipConfig:getFirstFitnessEquipId() --当前健身器材id
    self.unlockFitnessEquipId = FitnessEquipConfig:getFirstFitnessEquipId() --解锁健身器材id
    self.level = 0 --阶数等级
    self.advancedLevel = 0 --进阶等级
    self.muscleMass = GameConfig.muscleMass --肌肉量
    self.extraMuscle = 0 --额外肌肉量
    self.curHealth = self:getMaxHealth() --当前血量
    self.maxHealth = self:getMaxHealth() --最大血量
    self.gold = BigNum.new("0") --金币
    self.invincible = false --无敌状态
    --self.invincibleStartTime = os.time()
    self.isHoldItemActor = true
    self.isWorkoutMode = true --当前是否处于锻炼模式
    self.loginTime = 0
    self.advAutoWork = false --是否是看广告自动锻炼
    self.selectMode = Define.SelectMode.Equip
    self.lastUpdateScaleTime = 0
    self.lastScale = 0
    self.inAutoArea = false --是否在自动锻炼区
    self.championShipCoin = 0 --锦标赛代币
    self.exchangeReward = self.exchangeReward or {}

    --排行榜相关信息
    self.fame = "" --称号
    self.lastKill = 0  --杀人数
    self.kill = 0  --杀人数
    self.wrestlingKill = 0 --摔跤大赛击杀数
    self.isWrestling = false --是否在摔跤大赛区域

    --AutoWorkout传送到自动锻炼区前的开始坐标
    self.autoWorkoutPos = VectorUtil.ZERO
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if player then
        self.autoWorkoutPos = player:randomInitPos()
    end

end

function PlayerProperty:loadProperty(data)
    LogUtil.log(string.format("PlayerProperty:loadProperty %s", tostring(self.userId)))

    --还原属性数据
    if not data.__first then
        self.geneId = data.geneId or self.geneId
        self.geneId = GeneConfig:getValidGeneId(self.geneId)
        if FitnessEquipConfig:isValidId(data.fitnessEquipId) or TokenFitnessEquipConfig:isValidId(data.fitnessEquipId) then
            self.fitnessEquipId = data.fitnessEquipId or self.fitnessEquipId
        end
        self.unlockFitnessEquipId = data.unlockFitnessEquipId or self.unlockFitnessEquipId
        self.advancedLevel = data.advancedLevel or self.advancedLevel
        self.muscleMass = data.muscleMass or self.muscleMass
        if data.goldBig then
            local bigNum = BigNum.new(data.goldBig)
            if bigNum >= BigNum.new("0") then
                self.gold = bigNum
            end
        end
        local config = AdvancedConfig:getAdvancedConfig(self.advancedLevel)
        if config then
            self.level = config.level
        end
        self.kill = data.kill or 0
        self.lastKill = self.kill
        self.championShipCoin = data.championShipCoin or 0
        for propsType, time in pairs(data.exchangeReward or {}) do
            self:changeExchangeRewardTime(propsType, time - os.time())
        end
        print("exchangeReward", inspect.inspect(data.exchangeReward), inspect.inspect(self.exchangeReward))
    end
end

function PlayerProperty:hasPayItem(payItemType)
    return self.payItemList[tostring(payItemType)] ~= nil or self:hasExchangeReward(exchangeRewardMap[payItemType])
end

function PlayerProperty:hasExchangeReward(propsType)
    self:checkExchangeRewardTime(propsType)
    return self.exchangeReward[propsType] ~= nil
end

function PlayerProperty:checkExchangeRewardTime(propsType)
    local time = self.exchangeReward[propsType]
    if time and os.time() >= time then
        self.exchangeReward[propsType] = nil
    end
end

function PlayerProperty:changeExchangeRewardTime(propsType, time)
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end

    self:checkExchangeRewardTime(propsType)

    local lastTime = self.exchangeReward[propsType]

    self.exchangeReward[propsType] = self.exchangeReward[propsType] or os.time()
    self.exchangeReward[propsType] = self.exchangeReward[propsType] + time

    if lastTime == nil or lastTime ~= self.exchangeReward[propsType] then
        GamePacketSender:sendExchangeReward(player.rakssid, propsType, self.exchangeReward[propsType] - os.time())
        --print("GamePacketSender:sendExchangeReward", propsType,
        --        self.exchangeReward[propsType], os.time(), self.exchangeReward[propsType] - os.time())
    end
end

function PlayerProperty:getSavePayData()
    local data = {}
    data.payItemList = self.payItemList
    data.skinList = self.skinList
    data.skinId = self.skinId
    data.showSelectSkinDlg = self.showSelectSkinDlg
    return data
end

function PlayerProperty:loadPayData(data)
    local player = PlayerManager:getPlayerByUserId(self.userId)

    if not data.__first then
        self.payItemList = data.payItemList or {}
        self.skinList = data.skinList or {}
        self.skinId = data.skinId or -1
        if data.showSelectSkinDlg ~= nil then
            self.showSelectSkinDlg = data.showSelectSkinDlg
        end
    end

    self.skinList[tostring(SkinConfig:getDefaultSkin(player))] = 1

    self.loadDataFinish = true

    LogUtil.log(string.format("PlayerProperty:loadPayData payItemList:%s skinList:%s showSelectSkinDlg:%s",
            inspect.inspect(self.payItemList), inspect.inspect(self.skinList), tostring(self.showSelectSkinDlg)))

    self:changeHealth(self:getMaxHealth(), self:getMaxHealth(), false)

    self:syncProperty()

    if player then
        GamePacketSender:SendPlayerGoldChange(player.rakssid, self.gold)
        GamePacketSender:SendPlayerTokenNumChange(player.rakssid, self.championShipCoin)
        player:equipSkin(self.skinId)
    end

    self:syncPayData()
end

function PlayerProperty:syncPayData()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    local params = {}
    params.payItemList = Utility.tableToString(self.payItemList)
    params.skinList = Utility.tableToString(self.skinList)
    params.skinId = self.skinId
    params.showSelectSkinDlg = self.showSelectSkinDlg
    local data = DataBuilder.new():fromTable(params):getData()
    PacketSender:sendLuaCommonData(player.rakssid, "PayDataInit", data)
    --print(string.format("PlayerProperty:syncPayData payItemList:%s skinList:%s skinId:%d",
    --        params.payItemList, params.skinList, params.skinId))
end

function PlayerProperty:syncProperty()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if player then
        --同步属性数据到客户端
        local params = {
            geneId = self.geneId,
            fitnessEquipId = self.fitnessEquipId,
            unlockFitnessEquipId = self.unlockFitnessEquipId,
            advancedLevel = self.advancedLevel,
            muscleMass = self.muscleMass,
            maxMuscleMass = self:getMaxMuscleMass(),
            muscleMassCoe = self.muscleMassCoe,
            --curHealth = self.curHealth,
            --baseHealth = GameConfig.baseHealth
        }
        local data = DataBuilder.new():fromTable(params):getData()
        PacketSender:sendLuaCommonData(player.rakssid, "PlayerPropertyInit", data)
        player:setScale(self:getScale())
    end

    --print(string.format("PlayerProperty:syncProperty advancedLevel:%d", self.advancedLevel))
end

