--生命值上限大小
function PlayerProperty:getMaxHealth()
    local value = GameConfig.baseHealth + self.muscleMass * self.muscleMassCoe * self:getAdvancedCoe(Define.AdvancedCoeType.Hp)
    local privilegeCoe = self.payItemList[tostring(Define.PayItemType.DoubleHp)] or 0
    value = value * (1 + privilegeCoe)
    return math.ceil(value)
end

--伤害大小
function PlayerProperty:getAttack(skillId)
    local damageCoe = GameConfig.damageCoe
    if skillId then
        damageCoe = SkillConfig:getSkillHurt(skillId)
    end
    local privilegeCoe = self.payItemList[tostring(Define.PayItemType.DoubleDamage)] or 0
    local value = GameConfig.baseDamage + ((self.muscleMass + self.extraMuscle) * damageCoe * self:getAdvancedCoe(Define.AdvancedCoeType.Attack))
    value = value * (1 + privilegeCoe)
    return math.ceil(value)
end

--技能伤害
function PlayerProperty:getSkillAttack(skillId)
    local damageCoe = SkillConfig:getSkillHurt(skillId)
    local privilegeCoe = self.payItemList[tostring(Define.PayItemType.DoubleDamage)] or 0
    local value = GameConfig.baseDamage + ((self.muscleMass) * damageCoe * self:getAdvancedCoe(Define.AdvancedCoeType.Attack))
    value = value * (1 + privilegeCoe)
    LogUtil.log(string.format("PlayerProperty:getSkillAttack %f", damageCoe))
    return math.ceil(value)
end

function PlayerProperty:getAdvancedCoe(coeType)
    local config = AdvancedConfig:getAdvancedConfig(self.advancedLevel)
    if config == nil then
        return 1
    end

    if coeType == Define.AdvancedCoeType.Attack then
        return config.attack
    elseif coeType == Define.AdvancedCoeType.Efficiency then
        return config.workout
    elseif coeType == Define.AdvancedCoeType.MoveSpeed then
        return config.speed
    elseif coeType == Define.AdvancedCoeType.Hp then
        return config.hpCoe
    end

    return 1
end

--体型大小
function PlayerProperty:getScale()
    --return ScaleRuleConfig:getScale(self.muscleMass)
    return ScaleFormulaConfig:getScale(self.muscleMass)
end

--获得锻炼效率
function PlayerProperty:getMuscleMassInc()
    local privilegeCoe = self:hasPayItem(Define.PayItemType.DoubleMuscle) and 1 or 0
    local value = 0
    if FitnessEquipConfig:isPayFitnessEquip(self.fitnessEquipId) then
        local config = FitnessEquipConfig:getPayFitnessEquipConfig(self.fitnessEquipId)
        if not config then
            return 1
        end

        if self.advancedLevel < config.unlockAdvancedLevel then
            return 1
        end

        local isInfinityMuscle = self.payItemList[tostring(Define.PayItemType.InfinityMuscle)] or 0
        if isInfinityMuscle ~= 0 then
            return config.efficiencyFixHuge * self:getAdvancedCoe(Define.AdvancedCoeType.Efficiency) * (1 + privilegeCoe)
        end

        if self.advancedLevel < config.invailedAdvancedLevel then
            value = self:getMaxMuscleMass() * config.efficiencyPercentage * 0.01
        else
            value = config.efficiencyFix * self:getAdvancedCoe(Define.AdvancedCoeType.Efficiency) * (1 + privilegeCoe)
        end
    else
        value = FitnessEquipConfig:getEfficiency(self.fitnessEquipId) *
                self:getAdvancedCoe(Define.AdvancedCoeType.Efficiency) * (1 + privilegeCoe)
    end
    return math.ceil(value)
end

--生命恢复
function PlayerProperty:getLifeRecovery()
    local value = self:getMaxHealth() * GameConfig.lifeRecoveryCoe
    return math.ceil(value)
end

--肌肉量上限
function PlayerProperty:getMaxMuscleMass()
    local value = math.ceil(GameConfig.maxMuscleMass + GeneConfig:getGeneMuscleMass(self.geneId))
    if value <= 0 then
        value = 30
    end

    local privilegeCoe = self.payItemList[tostring(Define.PayItemType.InfinityMuscle)] or 0
    if privilegeCoe ~= 0 then
        return math.huge
    else
        return value
    end
end

--移动速度
function PlayerProperty:getMoveSpeed()
    local advancedCoe = self:getAdvancedCoe(Define.AdvancedCoeType.MoveSpeed)
    local privilegeCoe = self:hasPayItem(Define.PayItemType.DoubleSpeed) and 1 or 0

    local value = (GameConfig.baseMoveSpeedModify + GameConfig.baseMoveSpeed * self:getScale()) +
            (500 + GameConfig.baseMoveSpeedModify) * ((advancedCoe - 1) + (advancedCoe * privilegeCoe))

    return math.ceil(value)
end

function PlayerProperty:onLifeRecovery(ticks)
    if self.curHealth <= 0 or self.curHealth >= self:getMaxHealth() then
        return
    end

    if self:getLifeRecovery() == 0 then
        return
    end

    --print("PlayerProperty:onLifeRecovery " .. ticks)
    self:changeHealth(self.curHealth, self.curHealth + self:getLifeRecovery(), true)
end

function PlayerProperty:onRespawn()
    LogUtil.log("PlayerProperty:onRespawn " .. tostring(self.userId))
end

function PlayerProperty:onAfterRespawn()
    self:changeHealth(self:getMaxHealth(), self:getMaxHealth(), false)

    self:syncProperty()

    local player = PlayerManager:getPlayerByUserId(self.userId)
    if player then
        player:equipSkin(self.skinId)
        self:addInvincibleState()
        PacketSender:syncEntityPlayerInfo(player.userId, "ConcealPower", self.isConcealPower)
    end
end

function PlayerProperty:onTick(ticks)
    --self:updateInvincibleState()

    if ticks % (GameConfig.lifeRecoveryTime * GameMatch.tickPerSecond) == 0 then
        self:onLifeRecovery(ticks)
    end
end

--添加无敌状态
function PlayerProperty:addInvincibleState(time, removeEffect)
    time = time or GameConfig.invincibleTime
    removeEffect = removeEffect or false

    self.invincible = true

    local player = PlayerManager:getPlayerByUserId(self.userId)
    if player then
        if not removeEffect then
            player:addCustomEffect("InvincibleEffect" .. tostring(player.userId), GameConfig.SafeAreaEffect, time * 1000)
        end
        PacketSender:syncEntityPlayerInfo(player.userId, "Invincible", tostring(true))
    end

    LuaTimer:cancel(self.invincibleTimer)

    self.invincibleTimer = LuaTimer:scheduleTimer(function()
        self:removeInvincibleState()
    end, time * 1000, 1)
end

