--移除无敌状态
function PlayerProperty:removeInvincibleState()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if player then
        player:addCustomEffect("InvincibleEffect" .. tostring(player.userId), GameConfig.SafeAreaEffect, 0)
        PacketSender:syncEntityPlayerInfo(player.userId, "Invincible", tostring(false))
    end

    self.invincible = false

    LuaTimer:cancel(self.invincibleTimer)

    --print(string.format("PlayerProperty:removeInvincibleState %s", tostring(self.userId)))
end

function PlayerProperty:changeMuscleMass(muscle, immediateSync)
    if immediateSync == nil then
        immediateSync = true
    end

    local lastMuscleMass = self.muscleMass

    self.muscleMass = self.muscleMass + muscle
    self.muscleMass = MathUtil:bound(self.muscleMass, 0, self:getMaxMuscleMass())

    if self.muscleMass == lastMuscleMass then
        return
    end

    local newScale = self:getScale()
    if newScale ~= self.lastScale then
        local player = PlayerManager:getPlayerByUserId(self.userId)
        if player then
            if immediateSync then
                player:setScale(newScale)
            else
                if os.time() - self.lastUpdateScaleTime >= 1 or
                        math.abs(newScale - self.lastScale) >= 0.1 then
                    player:setScale(newScale)
                end
            end
        end
    end

    self:changeHealth(self.curHealth, self.curHealth, true)

    local player = PlayerManager:getPlayerByUserId(self.userId)
    if player then
        --检查体型，发送肌肉值改变事件
        GamePacketSender:SendLSPlayerMuscleMassChange(player.rakssid, self:getMaxMuscleMass(), self.muscleMass)
        --排行榜改变
        LSRankManager:updatePlayerRank(player)
        --组队事件
        TeamManager:onChangeMuscleMass(player)
    end

    --print(string.format("PlayerProperty:changeMuscleMass %s %s %s",
    --        tostring(self.userId), tostring(self.muscleMass), tostring(self:getMaxMuscleMass())))
end

function PlayerProperty:changeGold(goldNum)
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if player == nil then
        return
    end
    if type(goldNum) == "number" then
        goldNum = string.format("%f", goldNum)
    end
    self.gold = self.gold + goldNum
    if self.gold < BigNum.new("0") then
        self.gold = BigNum.new("0")
    end
    GamePacketSender:SendPlayerGoldChange(player.rakssid, self.gold)
end

function PlayerProperty:changeToken(tokenNum)
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if player == nil then
        return
    end
    self.championShipCoin = self.championShipCoin + tokenNum
    GamePacketSender:SendPlayerTokenNumChange(player.rakssid, self.championShipCoin)
end

function PlayerProperty:changeHealth(oldHealth, newHealth, changeSingle)
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if player == nil then
        return
    end

    if player:isEntityAlive() == false then
        return
    end

    local maxHealth = self:getMaxHealth()
    oldHealth = MathUtil:bound(oldHealth, 0, maxHealth)
    newHealth = MathUtil:bound(newHealth, 0, maxHealth)

    --if maxHealth == self.maxHealth and oldHealth == newHealth then
    --    return
    --end

    if changeSingle and player:getHealth() <= maxHealth then
        player:changeMaxHealthSingle(maxHealth)
    else
        player:changeMaxHealth(maxHealth)
    end

    local sub = newHealth - oldHealth
    if sub > 0 then
        player:addHealth(sub)
    elseif sub < 0 then
        player:setEntityHealth(newHealth)
    end

    --print(string.format("PlayerProperty:changeHealth %d %d %d", oldHealth, newHealth, self.maxHealth))
end

function PlayerProperty:changeHoldItemActor(id)
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end

    local actorName = "nil"
    local config = FitnessEquipConfig:getFitnessEquipConfig(id)
    if config then
        actorName = config.actor
    else
        local tokenConfig = TokenFitnessEquipConfig:getFitnessEquipConfig(id)
        if tokenConfig then
            actorName = tokenConfig.actor
        end
    end

    player.entityPlayerMP:setHoldItemActor(actorName)
    self.isHoldItemActor = (actorName ~= "nil")
    self.isWorkoutMode = id ~= 0
    if self.selectMode ~= Define.SelectMode.Equip and actorName ~= "nil" then
        --TODO
    else
        PacketSender:syncEntityPlayerInfo(self.userId, "HoldItemActor", actorName)
    end
    if not self.isWorkoutMode then
        TeamManager:destroyTeam(player) --不是锻炼模式需要解散读物
    end
    --LogUtil.log(string.format("PlayerProperty:changeHoldItemActor %d %s", id, actorName))
end

function PlayerProperty:changeFitnessEquipId(curId, maxId)
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    self.fitnessEquipId = curId
    self.unlockFitnessEquipId = maxId or self.unlockFitnessEquipId
    GamePacketSender:SendLSFitnessEquipChange(player.rakssid, self.fitnessEquipId, self.unlockFitnessEquipId)
    self:changeHoldItemActor(curId)
end

function PlayerProperty:changeGene(geneId)
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    local lastGeneId = self.geneId
    if geneId == lastGeneId then
        return
    end

    self.geneId = geneId

    GamePacketSender:SendLSGeneChange(player.rakssid, self.geneId, self:getMaxMuscleMass())
    GamePacketSender:SendLSPlayerMuscleMassChange(player.rakssid, self:getMaxMuscleMass(), self.muscleMass)
end

function PlayerProperty:setSpeedAdd()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if player then
        player.entityPlayerMP:setSpeedAdditionLevel(self:getMoveSpeed())
    end
end

function PlayerProperty:changeAdvancedLevel(level)
    --local last = self.advancedLevel
    --if level == last then
    --    return
    --end

    self.advancedLevel = level

    self:setSpeedAdd()

    self:changeHealth(self.curHealth, self.curHealth, false)

    --同步进阶等级改变
    local config = AdvancedConfig:getAdvancedConfig(self.advancedLevel)
    if config then
        self.level = config.level
        local player = PlayerManager:getPlayerByUserId(self.userId)
        PacketSender:syncEntityPlayerInfo(player.userId, "AdvancedLevel", tostring(self.advancedLevel))
    end

    local userId = self.userId
    local advancedLevel = self.advancedLevel
    local advanConfig = AdvancedConfig:getAdvancedConfig(advancedLevel)
    if advanConfig then
        advancedLevel = advanConfig.gradeId
        if userId and advancedLevel and advancedLevel > 0 then
            LogUtil.log("LiftingSimulatorWeb:UploadLv userId: " .. tostring(userId) .. " lv: " .. advancedLevel)
            LiftingSimulatorWeb:UploadLv(userId, advancedLevel)
        end
    end
end

function PlayerProperty:onHealthChanged(old_health, new_health)
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end

    --LogUtil.log(string.format("PlayerProperty:onHealthChanged %s %s %s",
    --        tostring(self.userId), tostring(old_health), tostring(new_health)))

    self.curHealth = new_health
    --self.maxHealth = self:getMaxHealth()

    if self.curHealth <= 0 then
        player:unbindAllEntity()
    end

    GamePacketSender:SendLSPlayerHealthChange(player.rakssid, self.curHealth, self.maxHealth)
end

function PlayerProperty:onChangeMaxHealthSingle(maxHealth)
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    self.maxHealth = maxHealth
    GamePacketSender:SendLSPlayerHealthChange(player.rakssid, self.curHealth, self.maxHealth)
end

function PlayerProperty:changeChampionShipCoin(value)
    self.championShipCoin = self.championShipCoin + value
end

return PlayerProperty
